int AudioLooper::optimizeLoopEnd(const float* data, int loopStart, int loopEnd, int bufLen) const {
    int win = std::min(XCORR_WINDOW, (loopEnd - loopStart) / 4);
    if (win < 16) return loopEnd;
    int searchLo = std::max(loopStart + win * 2, loopEnd - XCORR_SEARCH);
    int searchHi = std::min(bufLen, loopEnd + XCORR_SEARCH);
    float bestCorr = -1e30f;
    int bestEnd = loopEnd;
    for (int cand = searchLo; cand < searchHi; ++cand) {
        int eStart = cand - win;
        if (eStart < loopStart) continue;
        float sum = 0.0f, normA = 0.0f, normB = 0.0f;
        for (int j = 0; j < win; ++j) {
            float a = data[loopStart + j];
            float b = data[eStart + j];
            sum += a * b;
            normA += a * a;
            normB += b * b;
        }
        float denom = std::sqrt(normA * normB);
        float corr = denom > 0.0f ? sum / denom : 0.0f;
        if (corr > bestCorr) {
            bestCorr = corr;
            bestEnd = cand;
        }
    }
    return bestEnd;
}

Original-Code (TypeScript):
function applyLoopProcessing(ac, source, loopStart, loopEnd, optimize, crossfadeMs) {
  const copy = ac.createBuffer(source.numberOfChannels, source.length, source.sampleRate)
  for (let ch = 0; ch < source.numberOfChannels; ch++) {
    copy.getChannelData(ch).set(source.getChannelData(ch))
  }
  let actualEnd = loopEnd
  if (optimize && source.numberOfChannels > 0) {
    actualEnd = optimizeLoopEndSample(source.getChannelData(0), loopStart, loopEnd)
  }
  const loopLen = actualEnd - loopStart
  const fadeSamples = Math.min(
    Math.floor(crossfadeMs / 1000 * source.sampleRate),
    Math.floor(loopLen / 2),
  )
  if (fadeSamples >= 2) {
    for (let ch = 0; ch < copy.numberOfChannels; ch++) {
      const d = copy.getChannelData(ch)
      for (let i = 0; i < fadeSamples; i++) {
        const t = i / fadeSamples
        const gHead = Math.sin(t * Math.PI * 0.5)
        const gTail = Math.cos(t * Math.PI * 0.5)
        const headIdx = loopStart + i
        const tailIdx = actualEnd - fadeSamples + i
        d[headIdx] = d[headIdx]! * gHead + d[tailIdx]! * gTail
      }
    }
    actualEnd -= fadeSamples
  }
  return { buffer: copy, optimizedEnd: actualEnd, fadeSamples }
}

Legacy-JUCE (C++):
void AudioLooper::applyLoopCrossfade(juce::AudioBuffer<float>& buf, int loopStart, int& loopEnd) const {
    int loopLen = loopEnd - loopStart;
    int fadeSamples = std::min(
        static_cast<int>(crossfadeMsVal / 1000.0f * static_cast<float>(bufferOriginalSR)),
        loopLen / 2
    );
    if (fadeSamples < 2) return;
    const float pi_half = juce::MathConstants<float>::halfPi;
    for (int ch = 0; ch < buf.getNumChannels(); ++ch) {
        float* d = buf.getWritePointer(ch);
        for (int i = 0; i < fadeSamples; ++i) {
            float t = static_cast<float>(i) / static_cast<float>(fadeSamples);
            float gHead = std::sin(t * pi_half);
            float gTail = std::cos(t * pi_half);
            int headIdx = loopStart + i;
            int tailIdx = loopEnd - fadeSamples + i;
            d[headIdx] = d[headIdx] * gHead + d[tailIdx] * gTail;
        }
    }
    loopEnd -= fadeSamples;
}

Original-Code (TypeScript):
function createPalindromeBuffer(ac, source, loopStart, loopEnd) {
  const loopLen = loopEnd - loopStart
  if (loopLen < 4) return { buffer: source, palindromeEnd: loopEnd }
  const reverseLen = loopLen - 2
  const newLen = source.length + reverseLen
  const result = ac.createBuffer(source.numberOfChannels, newLen, source.sampleRate)
  for (let ch = 0; ch < source.numberOfChannels; ch++) {
    const src = source.getChannelData(ch)
    const dst = result.getChannelData(ch)
    for (let i = 0; i < loopEnd; i++) dst[i] = src[i]!
    for (let i = 0; i < reverseLen; i++) {
      dst[loopEnd + i] = src[loopEnd - 2 - i]!
    }
    for (let i = loopEnd; i < src.length; i++) {
      dst[i + reverseLen] = src[i]!
    }
  }
  return { buffer: result, palindromeEnd: loopEnd + reverseLen }
}

Legacy-JUCE (C++):
void AudioLooper::createPalindrome(const juce::AudioBuffer<float>& src, int loopStart, int loopEnd,
                                    juce::AudioBuffer<float>& dest, int& palindromeEnd) const {
    int loopLen = loopEnd - loopStart;
    if (loopLen < 4) {
        dest.makeCopyOf(src);
        palindromeEnd = loopEnd;
        return;
    }
    int reverseLen = loopLen - 2;
    int newLen = src.getNumSamples() + reverseLen;
    int numCh = src.getNumChannels();
    dest.setSize(numCh, newLen, false, false, true);
    for (int ch = 0; ch < numCh; ++ch) {
        const float* s = src.getReadPointer(ch);
        float* d = dest.getWritePointer(ch);
        for (int i = 0; i < loopEnd; ++i) d[i] = s[i];
        for (int i = 0; i < reverseLen; ++i) d[loopEnd + i] = s[loopEnd - 2 - i];
        for (int i = loopEnd; i < src.getNumSamples(); ++i) d[i + reverseLen] = s[i];
    }
    palindromeEnd = loopEnd + reverseLen;
}

